import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Cpu, Lock, Mail, Eye, EyeOff } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!email || !password) {
      toast.error('Please enter email and password');
      return;
    }

    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back!');
      navigate('/dashboard');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Login failed. Please check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="vault-card reveal-node">
      {/* Ambient glow effect */}
      <div className="absolute -top-32 -left-32 w-64 h-64 bg-emerald-600/20 blur-[120px] pointer-events-none" />
      
      {/* Header */}
      <div className="text-center mb-8">
        <div className="flex justify-center mb-5">
          <div className="p-4 bg-emerald-500/10 rounded-2xl">
            <Cpu size={36} className="text-emerald-400 animate-pulse" />
          </div>
        </div>
        <h1 className="text-2xl sm:text-3xl font-light tracking-tight text-white mb-2">
          Welcome Back
        </h1>
        <p className="text-white/40 text-xs uppercase tracking-widest font-mono">
          Sign in to your account
        </p>
      </div>

      {/* Form */}
      <form onSubmit={handleSubmit} className="space-y-5">
        {/* Email */}
        <div className="space-y-2">
          <label className="flex items-center gap-2 text-xs text-emerald-400 font-bold uppercase tracking-widest ml-1">
            <Mail size={14} /> Email Address
          </label>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="cyber-input"
            placeholder="you@example.com"
            required
          />
        </div>

        {/* Password */}
        <div className="space-y-2">
          <label className="flex items-center gap-2 text-xs text-emerald-400 font-bold uppercase tracking-widest ml-1">
            <Lock size={14} /> Password
          </label>
          <div className="relative">
            <input
              type={showPassword ? "text" : "password"}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="cyber-input pr-12"
              placeholder="••••••••"
              required
            />
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-4 top-1/2 -translate-y-1/2 text-white/40 hover:text-white/60 transition-colors"
            >
              {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          </div>
        </div>

        {/* Submit */}
        <button
          type="submit"
          disabled={loading}
          className="cyber-btn mt-6"
        >
          {loading ? 'Signing in...' : 'Sign In'}
        </button>
      </form>

      {/* Footer */}
      <div className="mt-8 pt-6 border-t border-white/5 text-center">
        <p className="text-xs text-white/40 uppercase tracking-widest">
          Don't have an account?{' '}
          <Link to="/register" className="text-emerald-400 hover:underline transition-colors">
            Sign Up
          </Link>
        </p>
      </div>
    </div>
  );
};

export default LoginPage;
